import pytest from sqlalchemy import create_engine from sqlalchemy.orm import sessionmaker from testcontainers.postgres import PostgresContainer from app.db import Base
@pytest.fixture(scope="session") def _engine(): with PostgresContainer("postgres:16.2") as pg: eng = create_engine(pg.get_connection_url()) Base.metadata.create_all(eng) yield eng
@pytest.fixture def db_session(_engine): conn = _engine.connect() tx = conn.begin() Session = sessionmaker(bind=conn) s = Session() try: yield s finally: s.close() tx.rollback() conn.close()

import pytest
from fastapi.testclient import TestClient
from app.main import app
from app.deps import get_db

@pytest.fixture
def client(db_session):
    def override_get_db():
        yield db_session
    app.dependency_overrides[get_db] = override_get_db
    with TestClient(app) as c:
        yield c
    app.dependency_overrides.clear()

class TestUserAPI:
    def test_create_user_success(self, client):
        response = client.post("/api/users", json={
            "email": "new@example.com",
            "name": "New User",
        })
        assert response.status_code == 201
        data = response.json()
        assert data["email"] == "new@example.com"
        assert "password" not in data

import pytest
from datetime import timedelta
from app.auth import create_access_token

@pytest.fixture
def auth_headers(test_user):
    token = create_access_token(
        data={"sub": test_user.id},
        expires_delta=timedelta(hours=1)
    )
    return {"Authorization": f"Bearer {token}"}
